Same pattern in `butterfly/page.tsx:22-58`, `journal/page.tsx:14-47`, `self/page.tsx:39-54`, `sensory/page.tsx:40-65`, `shadow/page.tsx:30-57`, `emotional/page.tsx:19-68`, `page.tsx:177-199`.

**Recommended extraction:**

```tsx
// hooks/useApiData.ts
import { useState, useEffect, useCallback } from 'react';

interface UseApiDataResult<T> {
  data: T | null;
  loading: boolean;
  error: string | null;
  reload: () => void;
}

export function useApiData<T>(
  fetcher: () => Promise<T>,
  deps: unknown[] = []
): UseApiDataResult<T> {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const result = await fetcher();
      setData(result);
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : 'Ошибка загрузки');
    } finally {
      setLoading(false);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, deps);

  useEffect(() => {
    load();
  }, [load]);

  return { data, loading, error, reload: load };
}
```

**Usage would reduce each page from ~15–30 lines of boilerplate to ~3:**

```tsx
const { data: sessions, loading, error, reload } = useApiData(
  () => reframingAPI.listSessions(),
  []
);
```

Estimated savings: ~30 lines × 8 pages = ~240 lines of duplicated hook boilerplate eliminated.
